(1000, 'PUBLISHED', 'A+B Problem', 1000, 65536, 'ĶŠōÕģźõĖżõĖ¬Ķć¬ńäČµĢ░, ĶŠōÕć║õ╗¢õ╗¼ńÜäÕÆī', 'õĖżõĖ¬Ķć¬ńäČµĢ░xÕÆīy (0<=x, y<=32767).', 'õĖĆõĖ¬µĢ░, ÕŹ│xÕÆīyńÜäÕÆī.', '123 500', '623', '## C++ Code\r\n\r\n    #include <iostream>\r\n\r\n    int main() {\r\n        int a = 0, b = 0;\r\n        std::cin >> a >> b;\r\n        std::cout << a + b << std::endl;\r\n        return 0;\r\n    }\r\n\r\n## Free Pascal Code\r\n\r\n    program Plus;\r\n    var a, b:longint;\r\n    begin\r\n        readln(a, b);\r\n        writeln(a + b);\r\n    end.\r\n\r\n## Java Code\r\n\r\n    import java.util.Scanner;\r\n\r\n    public class Main {\r\n        public static void main(String[] args) {\r\n            Scanner in = new Scanner(System.in);\r\n            int a = in.nextInt();\r\n            int b = in.nextInt();\r\n            System.out.println(a + b);\r\n        }\r\n    }\r\n'),
